          "C:\\Program Files\\SeaDrive\\seadrive.exe",
          "C:\\Program Files (x86)\\SeaDrive\\seadrive.exe",
        ];
  return paths.some((p) => {
    try {
      return existsSync(p);
    } catch {
      return false;
    }
  });
}

/** Best-effort process-list check. Never throws — returns false on any error. */
export function isSeaDriveRunning(): boolean {
